#!/usr/bin/env node
'use strict';

/**
 * p33-housekeeper-shadow-regression.test.js — P3.3 schema parser sees the
 * three new event rows.
 *
 * Verifies that `bin/regen-schema-shadow.js#parseEventSchemas` recognizes the
 * three new `### `<slug>` event` rows in `event-schemas.md`:
 *   - `housekeeper_action`
 *   - `housekeeper_drift_detected`
 *   - `housekeeper_forbidden_tool_blocked`
 *
 * Note: per the implementation brief, the shadow JSON
 * (`agents/pm-reference/event-schemas.shadow.json`) is regenerated by the PM
 * AFTER this W-item merges. We do NOT run `bin/regen-schema-shadow.js` from
 * this test. The parser-recognition assertion is the regression guard for
 * the markdown rows themselves.
 *
 * Runner: node --test bin/__tests__/p33-housekeeper-shadow-regression.test.js
 */

const { test, describe } = require('node:test');
const assert = require('node:assert/strict');
const fs = require('node:fs');
const path = require('node:path');

const REPO_ROOT = path.resolve(__dirname, '..', '..');
const EVENT_SCHEMAS_MD = path.join(REPO_ROOT, 'agents', 'pm-reference', 'event-schemas.md');
const SHADOW_JSON = path.join(REPO_ROOT, 'agents', 'pm-reference', 'event-schemas.shadow.json');

const { parseEventSchemas } = require('../regen-schema-shadow.js');

const NEW_SLUGS = [
  'housekeeper_action',
  'housekeeper_drift_detected',
  'housekeeper_forbidden_tool_blocked',
];

describe('P3.3 — three new schema rows are parser-visible', () => {

  test('event-schemas.md exists and is non-empty', () => {
    assert.ok(fs.existsSync(EVENT_SCHEMAS_MD), 'event-schemas.md missing');
    const stat = fs.statSync(EVENT_SCHEMAS_MD);
    assert.ok(stat.size > 1000, 'event-schemas.md unexpectedly small');
  });

  test('parseEventSchemas extracts all three housekeeper events', () => {
    const content = fs.readFileSync(EVENT_SCHEMAS_MD, 'utf8');
    const events = parseEventSchemas(content);
    assert.ok(Array.isArray(events) && events.length > 0,
      'parseEventSchemas must return a non-empty array');
    const slugs = events.map(e => e.slug);
    for (const expected of NEW_SLUGS) {
      assert.ok(slugs.includes(expected),
        'parseEventSchemas must extract `' + expected + '`.\n' +
        'Total events parsed: ' + events.length + '\n' +
        'Sample slugs: ' + slugs.slice(0, 12).join(', ') + '...\n' +
        'See agents/pm-reference/event-schemas.md — the row must use the\n' +
        '`### `<slug>` event` heading shape AND contain a ```json block\n' +
        'whose `"type"` field equals the slug.');
    }
  });

  test('each new event has version 1 in the parsed entry', () => {
    const content = fs.readFileSync(EVENT_SCHEMAS_MD, 'utf8');
    const events = parseEventSchemas(content);
    for (const expected of NEW_SLUGS) {
      const entry = events.find(e => e.slug === expected);
      assert.ok(entry, expected + ' entry missing');
      assert.equal(entry.version, 1,
        expected + ' should declare version 1; got: ' + entry.version);
    }
  });

  test('all three NEW_SLUGS are parser-visible regardless of shadow state', () => {
    // Shadow JSON regen happens via PostToolUse:Edit hook
    // (`bin/regen-schema-shadow-hook.js`) and is OUT OF this W-item's
    // control — the brief explicitly states the PM regenerates the shadow
    // after merge. So this assertion deliberately ignores the shadow's
    // event_count and only confirms that the parser sees all three new
    // rows in the source-of-truth markdown.
    const content = fs.readFileSync(EVENT_SCHEMAS_MD, 'utf8');
    const events = parseEventSchemas(content);
    const slugs = events.map(e => e.slug);
    const missing = NEW_SLUGS.filter(s => !slugs.includes(s));
    assert.equal(missing.length, 0,
      'parser must extract all three new P3.3 slugs from event-schemas.md.\n' +
      '  Missing: ' + JSON.stringify(missing) + '\n' +
      '  Total parsed: ' + events.length + '\n' +
      'Each row must use the `### `<slug>` event` heading shape AND a ```json\n' +
      'block whose `"type"` field equals the slug.');
  });

  test('agents/pm-reference/event-schemas.shadow.json parses cleanly (no shape regression)', () => {
    if (!fs.existsSync(SHADOW_JSON)) {
      // Acceptable: shadow may not exist on a fresh checkout — parser test
      // above is the binding assertion.
      return;
    }
    const shadow = JSON.parse(fs.readFileSync(SHADOW_JSON, 'utf8'));
    assert.ok(shadow && typeof shadow === 'object', 'shadow must parse as object');
    assert.ok(shadow._meta, 'shadow must include _meta');
  });

});
